    def search_documents(
        self,
        query: str = None,
        category: str = None,
        tags: List[str] = None,
        author: str = None,
        from_date: datetime = None,
        to_date: datetime = None,
        size: int = 10,
        from_: int = 0,
        sort_by: str = "_score",
        sort_order: str = "desc"
    ) -> Dict[str, Any]:
        must_queries = []
        filter_queries = []
        
        if query:
            must_queries.append({
                "multi_match": {
                    "query": query,
                    "fields": ["title^3", "content", "metadata.*"],
                    "type": "best_fields",
                    "fuzziness": "AUTO"
                }
            })
        
        if category:
            filter_queries.append({"term": {"category": category}})
        
        if tags:
            filter_queries.append({"terms": {"tags": tags}})
        
        if author:
            filter_queries.append({"term": {"author": author}})
        
        if from_date or to_date:
            date_range = {}
            if from_date:
                date_range["gte"] = from_date.isoformat()
            if to_date:
                date_range["lte"] = to_date.isoformat()
            filter_queries.append({"range": {"created_at": date_range}})
        
        search_body = {
            "query": {
                "bool": {
                    "must": must_queries if must_queries else [{"match_all": {}}],
                    "filter": filter_queries
                }
            },
            "size": size,
            "from": from_,
            "sort": [{sort_by: {"order": sort_order}}] if sort_by != "_score" else []
        }
        
        response = self.es.search(index=self.document_index, body=search_body)
        
        return {
            "total": response["hits"]["total"]["value"],
            "hits": [
                {
                    "id": hit["_id"],
                    "score": hit["_score"],
                    **hit["_source"]
                }
                for hit in response["hits"]["hits"]
            ]
        }
    
