class ElasticsearchLogger:
    def __init__(self, es_manager: ElasticsearchManager, logger_name: str = "app", service: str = "default"):
        self.es_manager = es_manager
        self.logger_name = logger_name
        self.service = service
    
    def debug(self, message: str, **kwargs):
        self.es_manager.log_message(
            level="DEBUG",
            message=message,
            logger=self.logger_name,
            service=self.service,
            **kwargs
        )
    
    def info(self, message: str, **kwargs):
        self.es_manager.log_message(
            level="INFO",
            message=message,
            logger=self.logger_name,
            service=self.service,
            **kwargs
        )
    
    def warning(self, message: str, **kwargs):
        self.es_manager.log_message(
            level="WARNING",
            message=message,
            logger=self.logger_name,
            service=self.service,
            **kwargs
        )
    
    def error(self, message: str, stack_trace: str = None, **kwargs):
        self.es_manager.log_message(
            level="ERROR",
            message=message,
            logger=self.logger_name,
            service=self.service,
            stack_trace=stack_trace,
            **kwargs
        )
    
    def critical(self, message: str, stack_trace: str = None, **kwargs):
        self.es_manager.log_message(
            level="CRITICAL",
            message=message,
            logger=self.logger_name,
            service=self.service,
            stack_trace=stack_trace,
            **kwargs
        )


